// tests/a11y/e2e-axe.spec.ts (Playwright)
import { test, expect } from '@playwright/test';
import AxeBuilder from '@axe-core/playwright';

test.describe('Chat UI accessibility regression', () => {
  test('chat interface passes axe on load', async ({ page }) => {
    await page.goto('/chat');
    const results = await new AxeBuilder({ page })
      .withTags(['wcag2a', 'wcag2aa', 'wcag21aa'])
      .analyze();

    const critical = results.violations.filter(v => v.impact === 'critical');
    const serious = results.violations.filter(v => v.impact === 'serious');

    // Budget: 0 critical, max 5 serious
    expect(critical.length).toBe(0);
    expect(serious.length).toBeLessThanOrEqual(5);

    // Report all violations for developer visibility
    if (results.violations.length > 0) {
      console.log('Accessibility violations found:');
      results.violations.forEach(v => {
        console.log(\`[\${v.impact}] \${v.id}: \${v.help} (WCAG: \${v.tags.join(', ')})\`);
        v.nodes.forEach(n => console.log(\`  Selector: \${n.target}\`));
      });
    }
  });

  test('chat interface passes axe after AI response loads', async ({ page }) => {
    await page.goto('/chat');
    // Send a test message and wait for AI response
    await page.fill('[aria-label="Message"]', 'Test accessibility scan');
    await page.keyboard.press('Enter');
    await page.waitForSelector('[data-testid="ai-response"]');

    const results = await new AxeBuilder({ page })
      .include('[data-testid="chat-container"]')
      .analyze();

    expect(results.violations.filter(v => v.impact === 'critical').length).toBe(0);
  });
});

// lighthouserc.js
module.exports = {
  ci: {
    collect: {
      url: [process.env.STAGING_URL + '/chat'],
      numberOfRuns: 3,
      settings: {
        onlyCategories: ['accessibility'],
        formFactor: 'desktop',
      },
    },
    assert: {
      assertions: {
        'categories:accessibility': ['error', { minScore: 0.90 }],
        // Fail on specific critical criteria
        'color-contrast': 'error',
        'html-has-lang': 'error',
        'image-alt': 'error',
        'input-image-alt': 'error',
        'label': 'error',
        // Warn on serious
        'aria-allowed-attr': 'warn',
        'aria-required-attr': 'warn',
      },
    },
    upload: {
      target: 'temporary-public-storage',
    },
  },
};
